import './CurrentStepVerticalTimeline.scss';

import type { FC } from 'react';
import React, { useMemo } from 'react';

import type { TimelineIconType } from '../../Timeline.types';
import { VerticalContent } from '../VerticalContent';
import type { CurrentStepVerticalTimelineProps } from './CurrentStepVerticalTimeline.types';

export const CurrentStepVerticalTimeline: FC<CurrentStepVerticalTimelineProps> = ({
	steps,
	completed,
	bottom = false,
	collapsable = false,
	collapsed = false,
}) => {
	const [step] = steps;

	const type: TimelineIconType = useMemo<TimelineIconType>(() => {
		if (completed) {
			return 'active';
		} else if (step?.error) {
			return 'error';
		}
		return 'current';
	}, [completed, step]);

	if (!step) {
		return null;
	}

	const position = completed || bottom ? 'bottom' : 'middle';

	return (
		<div data-testid="CurrentStepVerticalTimeline" key={step.id} className="dsb_timeline-current-step">
			<VerticalContent {...step} type={type} position={position} collapsable={collapsable} collapsed={collapsed} />
		</div>
	);
};
